	local roomGain = b.create("SimpleGain", samplerName + "_" + samplerNumber + "_Room", sampler, b.ChainIndexes.FX);

	return {
		sampler: sampler,
		directGain: directGain,
		monoGain: monoGain,
		ohGain: ohGain,
		roomGain: roomGain
	};
}

