const var v = [100, 200, 400, 800, 1600, 3200];

inline function getSnappedFrequency(value, snapEnabled)
{
	local idx = parseInt(Math.floor(value));

	if (snapEnabled)
		return v[idx];

	local lo = v[idx];
	local hi = v[idx + 1];
	local alpha = Math.fmod(value, 1.0);
	return lo * (1.0 - alpha) + hi * alpha;
}

